.rad-ui-accordion-root{
    //  --------------------------------
    //  --- Component Tokens -----
    //  --------------------------------
    
    --rad-accordion-border-color: var(--rad-ui-color-gray-700);
    --rad-accordion-background-color: var(--rad-ui-color-gray-50);
    --rad-accordion-text-color: var(--rad-ui-color-gray-1000);

    // Trigger Tokens
    --rad-accordion-trigger-background-color: var(--rad-ui-color-gray-50);
    --rad-accordion-trigger-text-color: var(--rad-ui-color-purple-950);

    // Content Tokens
    --rad-accordion-content-background-color: var(--rad-ui-color-gray-100);
    --rad-accordion-content-text-color: var(--rad-ui-color-gray-950);

    // Focus Tokens
    --rad-accordion-focus-border-color: var(--rad-ui-color-purple-800);
    --rad-accordion-focus-outline-offset: 1px;


    width: 100%;
    border: 1px solid var(--rad-accordion-border-color);
    border-radius: 4px;

    .rad-ui-accordion-item {
        border-radius: 4px;

        &[data-disabled]{
            opacity: 0.3;
            pointer-events: none;
            cursor: not-allowed !important;
        }
        
        background-color: var(--rad-accordion-background-color);

        // not last child
        &:not(:last-child){
            border-bottom: 1px solid var(--rad-accordion-border-color);
        }

        // Focus state for the entire item (when trigger or content is focused)
        &:focus-within {
            outline: 3px solid var(--rad-accordion-focus-border-color);
            outline-offset: var(--rad-accordion-focus-outline-offset);
        }

        .rad-ui-accordion-trigger{
            border-radius: 4px;
            width: 100%;
            text-align: left;
            padding:16px;
            font-size: 0.85rem;
            color: var(--rad-accordion-trigger-text-color);
            background-color: var(--rad-accordion-trigger-background-color);

            // Remove default focus outline since parent handles focus-within
            &:focus {
                outline: none;
            }

            // Focus-visible for keyboard navigation
            &:focus-visible {
                outline: none;
            }
        }

        .rad-ui-accordion-content {
            padding: 16px;
            font-size: 0.85rem;
            color: var(--rad-accordion-content-text-color);
            border-top: 1px solid var(--rad-accordion-border-color);
            background-color: var(--rad-accordion-content-background-color);

            &[data-state="open"]{
                height: auto;
                border-bottom-left-radius: 4px;
                border-bottom-right-radius: 4px;
            }

            // Remove default focus outline since parent handles focus-within
            &:focus {
                outline: none;
            }

            // Focus-visible for keyboard navigation
            &:focus-visible {
                outline: none;
            }
        }
    }
}

