  // Prevent text selection during drag
  user-select: none;
  
  // Handle touch interactions
  touch-action: none;
  overflow: hidden;
  border-radius: 12px;

  .rad-ui-splitter-panel {
    position: relative;
    overflow: hidden;
    
    // Ensure panels don't shrink below their flex-basis
    flex-shrink: 0;
    flex-grow: 0;
    
    // Allow content to scroll within panels
    overflow: auto;
    
    // Smooth transitions for size changes (optional)
    // transition: flex-basis 0.1s ease-out;
    
    // Prevent content from affecting layout during resize
    min-width: 0;
    min-height: 0;
  }

  .rad-ui-splitter-handle {
    position: relative;
    background: var(--rad-ui-color-gray-300);
    border: 1px solid var(--rad-ui-color-gray-400);
